import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/configuration.md","filePath":"guide/configuration.md"}'),i={name:"guide/configuration.md"};function n(d,t,s,l,c,g){return a(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>GeniusHRM provides a comprehensive admin settings panel accessible at <code>/admin/settings</code>. This panel lets you configure everything from branding and email to SMS, currency, and financial year — without touching any code.</p><hr><h2 id="accessing-system-settings" tabindex="-1">Accessing System Settings <a class="header-anchor" href="#accessing-system-settings" aria-label="Permalink to &quot;Accessing System Settings&quot;">​</a></h2><p>Navigate to <strong>Admin Panel → Settings</strong> in the sidebar, or go directly to <code>/admin/settings</code>. You must be logged in with the <strong>Admin</strong> role.</p><p>The settings panel is organised into the following tabs:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>General</strong></td><td>App name, logo, favicon, footer text</td></tr><tr><td><strong>Email (SMTP)</strong></td><td>Outgoing email configuration</td></tr><tr><td><strong>SMS</strong></td><td>SMS gateway setup (Twilio)</td></tr><tr><td><strong>Finance</strong></td><td>Financial year, currency, number format</td></tr><tr><td><strong>Date &amp; Time</strong></td><td>Timezone, date format, week start day</td></tr><tr><td><strong>Appearance</strong></td><td>Theme colour, login page background</td></tr></tbody></table><hr><h2 id="general-appearance-settings" tabindex="-1">General / Appearance Settings <a class="header-anchor" href="#general-appearance-settings" aria-label="Permalink to &quot;General / Appearance Settings&quot;">​</a></h2><p>The <strong>General</strong> tab controls branding elements visible across the entire application.</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Application Name</strong></td><td>Displayed in the browser tab and top navigation</td></tr><tr><td><strong>Logo</strong></td><td>Uploaded image shown in the header (SVG or PNG, max 2 MB)</td></tr><tr><td><strong>Favicon</strong></td><td>Browser tab icon (ICO or PNG, 32×32 px recommended)</td></tr><tr><td><strong>Footer Text</strong></td><td>Text displayed in the application footer</td></tr><tr><td><strong>Login Page Background</strong></td><td>Image shown on the authentication screens</td></tr></tbody></table><p><strong>Steps to update the logo:</strong></p><ol><li>Go to <strong>Settings → General</strong></li><li>Click <strong>Choose File</strong> next to the Logo field</li><li>Select an SVG or PNG file (recommended size: 200×60 px)</li><li>Click <strong>Save Settings</strong></li><li>Hard-refresh your browser (Ctrl+Shift+R / Cmd+Shift+R)</li></ol><hr><h2 id="smtp-email-setup" tabindex="-1">SMTP Email Setup <a class="header-anchor" href="#smtp-email-setup" aria-label="Permalink to &quot;SMTP Email Setup&quot;">​</a></h2><p>GeniusHRM uses Laravel&#39;s mail system. Configure SMTP credentials in the <strong>Email</strong> tab so the system can send password resets, leave notifications, payslips, and other automated emails.</p><h3 id="gmail-smtp" tabindex="-1">Gmail SMTP <a class="header-anchor" href="#gmail-smtp" aria-label="Permalink to &quot;Gmail SMTP&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Gmail App Passwords</p><p>Gmail requires an App Password if 2-Factor Authentication is enabled. Do not use your Google account password directly.</p></div><ol><li>Go to your <a href="https://myaccount.google.com/security" target="_blank" rel="noreferrer">Google Account Security</a></li><li>Enable 2-Step Verification if not already enabled</li><li>Generate an <strong>App Password</strong> (select &quot;Mail&quot; and &quot;Other device&quot;)</li><li>Enter the following in <strong>Settings → Email</strong>:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Mail Host</td><td><code>smtp.gmail.com</code></td></tr><tr><td>Mail Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td><code>tls</code></td></tr><tr><td>Mail Username</td><td><code>your.email@gmail.com</code></td></tr><tr><td>Mail Password</td><td>Your 16-character App Password</td></tr><tr><td>From Address</td><td><code>your.email@gmail.com</code></td></tr><tr><td>From Name</td><td><code>GeniusHRM</code></td></tr></tbody></table><h3 id="mailgun-smtp" tabindex="-1">Mailgun SMTP <a class="header-anchor" href="#mailgun-smtp" aria-label="Permalink to &quot;Mailgun SMTP&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Mail Host</td><td><code>smtp.mailgun.org</code></td></tr><tr><td>Mail Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td><code>tls</code></td></tr><tr><td>Mail Username</td><td><code>postmaster@mg.your-domain.com</code></td></tr><tr><td>Mail Password</td><td>Your Mailgun SMTP password</td></tr><tr><td>From Address</td><td><code>noreply@your-domain.com</code></td></tr></tbody></table><h3 id="mailtrap-development-testing" tabindex="-1">Mailtrap (Development / Testing) <a class="header-anchor" href="#mailtrap-development-testing" aria-label="Permalink to &quot;Mailtrap (Development / Testing)&quot;">​</a></h3><p>Mailtrap is ideal for development — it captures all outgoing emails without actually delivering them.</p><ol><li>Create a free account at <a href="https://mailtrap.io" target="_blank" rel="noreferrer">mailtrap.io</a></li><li>Go to <strong>Inboxes → SMTP Settings</strong></li><li>Copy the credentials into <strong>Settings → Email</strong>:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Mail Host</td><td><code>smtp.mailtrap.io</code></td></tr><tr><td>Mail Port</td><td><code>2525</code></td></tr><tr><td>Encryption</td><td><code>tls</code></td></tr><tr><td>Mail Username</td><td>Your Mailtrap username</td></tr><tr><td>Mail Password</td><td>Your Mailtrap password</td></tr></tbody></table><p>After saving, use the <strong>Send Test Email</strong> button to verify the connection.</p><hr><h2 id="sms-setup-twilio" tabindex="-1">SMS Setup (Twilio) <a class="header-anchor" href="#sms-setup-twilio" aria-label="Permalink to &quot;SMS Setup (Twilio)&quot;">​</a></h2><p>GeniusHRM integrates with Twilio for SMS notifications (e.g., leave approval alerts, OTPs).</p><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><ol><li>Create a <a href="https://www.twilio.com" target="_blank" rel="noreferrer">Twilio</a> account</li><li>Purchase a phone number with SMS capability</li><li>Note your <strong>Account SID</strong>, <strong>Auth Token</strong>, and <strong>Phone Number</strong></li></ol><h3 id="configuration-steps" tabindex="-1">Configuration Steps <a class="header-anchor" href="#configuration-steps" aria-label="Permalink to &quot;Configuration Steps&quot;">​</a></h3><ol><li>Go to <strong>Settings → SMS</strong></li><li>Toggle <strong>Enable SMS</strong> to on</li><li>Fill in the Twilio credentials:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>SMS Provider</td><td>Twilio</td></tr><tr><td>Account SID</td><td>Your Twilio Account SID (starts with <code>AC</code>)</td></tr><tr><td>Auth Token</td><td>Your Twilio Auth Token</td></tr><tr><td>From Number</td><td>Your Twilio phone number (e.g., <code>+15551234567</code>)</td></tr></tbody></table><ol start="4"><li>Click <strong>Save</strong></li><li>Enter a test phone number and click <strong>Send Test SMS</strong></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>SMS credits are consumed from your Twilio balance. Monitor usage in the Twilio dashboard to avoid running out of balance.</p></div><hr><h2 id="financial-year-configuration" tabindex="-1">Financial Year Configuration <a class="header-anchor" href="#financial-year-configuration" aria-label="Permalink to &quot;Financial Year Configuration&quot;">​</a></h2><p>The financial year setting affects payroll runs, leave balance resets, and report date ranges.</p><ol><li>Go to <strong>Settings → Finance</strong></li><li>Set the <strong>Financial Year Start Month</strong> (e.g., <code>January</code> for a Jan–Dec year, or <code>April</code> for an Apr–Mar year)</li><li>Set the <strong>Financial Year Start Day</strong> (usually <code>1</code>)</li><li>Click <strong>Save</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Changing the financial year after payroll runs have been processed can cause discrepancies in historical reports. Set this before processing any payroll.</p></div><hr><h2 id="timezone-and-date-format" tabindex="-1">Timezone and Date Format <a class="header-anchor" href="#timezone-and-date-format" aria-label="Permalink to &quot;Timezone and Date Format&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Recommended Values</th></tr></thead><tbody><tr><td><strong>Timezone</strong></td><td><code>UTC</code>, <code>Asia/Dhaka</code>, <code>America/New_York</code>, etc.</td></tr><tr><td><strong>Date Format</strong></td><td><code>Y-m-d</code>, <code>d/m/Y</code>, <code>m/d/Y</code></td></tr><tr><td><strong>Time Format</strong></td><td><code>H:i</code> (24-hour) or <code>h:i A</code> (12-hour)</td></tr><tr><td><strong>Week Starts On</strong></td><td><code>Monday</code> or <code>Sunday</code></td></tr></tbody></table><ol><li>Go to <strong>Settings → Date &amp; Time</strong></li><li>Select your timezone from the dropdown</li><li>Choose a date format (a preview shows the current date in the selected format)</li><li>Save changes</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use the same timezone in your PHP <code>php.ini</code> (<code>date.timezone</code>) and your server OS to avoid date drift issues.</p></div><hr><h2 id="currency-settings" tabindex="-1">Currency Settings <a class="header-anchor" href="#currency-settings" aria-label="Permalink to &quot;Currency Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Currency Code</strong></td><td>ISO 4217 code (e.g., <code>USD</code>, <code>BDT</code>, <code>GBP</code>)</td></tr><tr><td><strong>Currency Symbol</strong></td><td>Symbol displayed in the UI (e.g., <code>$</code>, <code>৳</code>, <code>£</code>)</td></tr><tr><td><strong>Symbol Position</strong></td><td>Before or after the amount</td></tr><tr><td><strong>Decimal Separator</strong></td><td><code>.</code> (period) or <code>,</code> (comma)</td></tr><tr><td><strong>Thousands Separator</strong></td><td><code>,</code> (comma) or <code>.</code> (period)</td></tr><tr><td><strong>Decimal Places</strong></td><td>Usually <code>2</code></td></tr></tbody></table><p>These settings affect salary displays, payslips, and all financial reports.</p><hr><h2 id="caching-configuration" tabindex="-1">Caching Configuration <a class="header-anchor" href="#caching-configuration" aria-label="Permalink to &quot;Caching Configuration&quot;">​</a></h2><p>After making changes to system settings, clear Laravel&#39;s cache to apply them immediately:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config:clear</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:clear</span></span></code></pre></div><p>Or use the <strong>Clear Cache</strong> button available in <strong>Settings → General</strong> (Admin panel).</p>`,56)])])}const u=e(i,[["render",n]]);export{p as __pageData,u as default};
